```python
from itertools import combinations


def powerset(min_features, max_features):
    for ln in range(min_features, max_features+1):
        for feature_set in combinations(range(max_features), r=ln):
            if feature_set:
                yield feature_set
    
            
min_features = 3
max_features = 8

for candidate in powerset(min_features, max_features):
    # evaluate
    pass
```

