class Stateful:
def get_state()
def set_state()

Seq2SeqEncoder(torch.nn.Module, Stateful, Registerable):
Seq2StackEncoder(torch.nn.Module, Stateful, Registerable):
Seq2VecEncoder(torch.nn.Module, Registerable):

class PytorchSeq2SeqWrapper(Seq2SeqWrapper):

