Hi guys, for the same issue, I proposed a similar solution by sharing the seed across input and target transform functions in Keras: https://github.com/fchollet/keras/issues/3338 . As mentioned above, that's too complicated to handle, my implementation is buggy and not thread-safe(the input and target can mis-synchronised). 

When moving to torch, I found the easy and robust way to implementing this kind of transformations is by merging and splitting image channels. 

The idea is to use one transform for handling both input and target images, by using `Merge()` and `Split`, we can merge input and target images along channel-dimension, and then we can apply the transform, after, we split it back. 

Here is my implementation:

```python
transform = EnhancedCompose([
    Merge(),              # merge input and target along the channel axis
    ElasticTransform(),
    RandomRotate(),
    Split([0,1],[1,2]),  # split into 2 images
    [CenterCropNumpy(size=input_shape), CenterCropNumpy(size=target_shape)],
    [NormalizeNumpy(), None],
    [Lambda(to_tensor), Lambda(to_tensor)]
])
```

```python
class EnhancedCompose(object):
    """Composes several transforms together, support separate transformations for multiple input.
    """
    def __init__(self, transforms):
        self.transforms = transforms

    def __call__(self, img):
        for t in self.transforms:
            if isinstance(t, collections.Sequence):
                assert isinstance(img, collections.Sequence) and len(img) == len(t), "size of image group and transform group does not fit"
                tmp_ = []
                for i, im_ in enumerate(img):
                    if callable(t[i]):
                        tmp_.append(t[i](im_))
                    else:
                        tmp_.append(im_)
                img = tmp_
            elif callable(t):
                img = t(img)
            elif t is None:
                continue
            else:
                raise Exception('unexpected type')                
        return img

class Merge(object):
    """Merge a group of images
    """
    def __init__(self, axis=-1):
        self.axis = axis
    def __call__(self, images):
        if isinstance(images, collections.Sequence) or isinstance(images, np.ndarray):
            assert all([isinstance(i, np.ndarray) for i in images]), 'only numpy array is supported'
            shapes = [list(i.shape) for i in images]
            for s in shapes:
                s[self.axis] = None
            assert all([s==shapes[0] for s in shapes]), 'shapes must be the same except the merge axis'
            return np.concatenate(images, axis=self.axis)
        else:
            raise Exception("obj is not a sequence (list, tuple, etc)")

class Split(object):
    """Split images into individual images
    """
    def __init__(self, *slices, **kwargs):
        assert isinstance(slices, collections.Sequence)
        slices_ = []
        for s in slices:
            if isinstance(s, collections.Sequence):
                slices_.append(slice(*s))
            else:
                slices_.append(s)
        assert all([isinstance(s, slice) for s in slices_]), 'slices must be consist of slice instances'
        self.slices = slices_
        self.axis = kwargs.get('axis', -1)

    def __call__(self, image):
        if isinstance(image, np.ndarray):
            ret = []
            for s in self.slices:
                sl = [slice(None)]*image.ndim
                sl[self.axis] = s
                ret.append(image[sl])
            return ret
        else:
            raise Exception("obj is not an numpy array")
```
Also note that, by doing this, I would propose to implement all the transformations with numpy and scipy.ndimage in torchvision, which is more powerful than PIL, and also to get rid of the limitations on the channel number and image mode that PIL can handle.

And this implementation can also support more than two image pairs, meaning sometimes we can have multiple inputs and outputs. For example, some kind of sample weight map which need to be transformed at the same time.

I have been using my implementation for a while and it helped me a lot. 
Let me know how do you think. if there is enough people interested, I could try to do a PR.

```python
import sys

from functools import wraps
from klein import route, run
from twisted.web.template import (
    tags, slot, TagLoader, Element, XMLString, XMLFile
)
from twisted.python.modules import getModule

def _callingModuleName(extra=0):
    """
    Return the name of the calling module.
    """
    return sys._getframe(2 + extra).f_globals('__name__')


_kw2loaderMapping = {
    'tags': TagLoader,
    'string': XMLString,
    'filename': lambda fn:
        XMLFile(getModule(_callingModuleName(1))
                .filePath.sibling(fn))
}


def _kw2loader(kwargs):
    """
    Convert the given C{kwargs} into a loader::

        _kw2loader(dict(tags=[...]))

    returns a L{TagLoader} with the given twisted.web.template stan objects, ::

        _kw2loader(dict(string='<html ...></html>'))

    will create a L{XMLString} from some XML, and ::

        _kw2loader(dict(file='foo.xml'))

    will create a L{XMLFile} from an XML file next to the Python file it's
    defined in.

    @return: a template loader based on the keyword arguments.
    @rtype: L{ITemplateLoader}
    """
    if len(kwargs) != 1:
        raise TypeError("pass only one type of loader, not {}"
                        .format(repr(kwargs.keys())))
    [[key, value]] = kwargs.items()
    return _kw2loaderMapping[key](value)



class Plating(object):
    """
    L{Plating} (as in: chrome-plating) represents the common elements of a page
    (borders, navigation, footer, etc) which can be applied to the content of
    multiple pages.
    """

    def __init__(self, *args, **kw):
        """
        Create L{Plating} with a set of default values and a loader.

        @param args: L{Plating} takes a single optional positional argument,
            the default values for all the slots in its template.

        @param kw: A loader for the plating portions of the template
            (header/footer/navigation) based on the rules explained in
            L{_kw2loader}.  This template should have at least one slot, called
            C{"content"}.
        """
        if args:
            [self.defaults] = args
        else:
            self.defaults = {}
        self.loader = _kw2loader(kw)


    def content(self, **kw):
        """
        L{Plating.content} is a decorator used to decorate a function which
        produces a dictionary of slot data.

        @param kw: A loader for the content portions of the template, which
            will be filled out with slot values from the return value of the
            decorated function.
        """
        loader = _kw2loader(kw)
        def decorate(thunk):
            @wraps(thunk)
            def decorator(*a, **k):
                slotData = self.defaults.copy()
                toFillWith = thunk(*a, **k)
                slotData.update(toFillWith)
                slotData.update(content=Element(loader=loader))
                [loaded] = self.loader.load()
                loaded = loaded.clone()
                return Element(
                    loader=TagLoader(
                        loaded.fillSlots(
                            **slotData
                        )
                    )
                )
            return decorator
        return decorate


plating = Plating(
    dict(
        title=u"JUST A TITLE",
        content=u"NEVER MIND THE CONTENT",
    ),
    tags=tags.html(
        tags.head(tags.title(slot("title"))),
        tags.body(
            tags.h1(slot("title")),
            tags.div(slot("content"),
                     Class="content")
        )
    ),
)

@route('/')
@plating.content(tags=tags.h2(tags.em(slot("subtitle"))))
def something(request):
    """
    Example usage of L{Plating}.
    """
    return dict(
        title=u"title displayed here",
        subtitle=u"and this stands in for some content"
    )

widgetPlating = Plating(
    tags=tags.div(
        tags.div(slot("title"), style="border: thin solid red;"),
        tags.div(slot("content"), style="border: thin solid green;"),
        style="border: thin solid blue;"
    )
)

@widgetPlating.content(tags=tags.div(slot("widget-contents")))
def widget(n):
    """
    A widget that fills a slot.
    """
    return {
        "title": u"widget-{}".format(n),
        "widget-contents": "the main event for widget {}".format(n)
    }

@route('/title')
@plating.content(tags=[])
def titleOnly(request):
    """
    Show the title only; fill out the content slot with nothing.
    """
    return dict(
        subtitle=u"title only"
    )

@route("/widget")
@plating.content(tags=[
    tags.div(slot("blub"), style="width: 49%; float: left"),
    tags.div(slot("blab"), style="width: 49%; float: left")
])
def widgetPage(request):
    """
    A page with 2 widgets, each with its own common plating.
    """
    return {
        "blub": widget(1),
        "blab": widget(2),
    }

run('localhost', 9000)
```

@NikolajBjorner  Here is a new solution https://github.com/Z3Prover/z3/compare/master...rainoftime:iss939fixnew?expand=1. The double free hasn't occurs with this patch. 

This commit is based on https://github.com/Z3Prover/z3/pull/940/files, but more lightweight.  When z3 times out at `sat_simplifier.cpp`, the `checkpoint2()` function will call `m_simplifier.finalize_m_visited()` to finalize the `m_visited`. 

It seems the trouble maker is the `m_visited` in `sat_simplifier.cpp`?

